class Solution:
    def specialPalindrome(self, n):
        from collections import Counter
        def special(x):
            s = str(x)
            if s != s[::-1]:
                return False
            c = Counter(s)
            return all(int(d) == cnt for d, cnt in c.items())
        x = n + 1
        while not special(x):
            x += 1
        return x

