class Solution:
    def specialPalindrome(self, n):
        def build(half_counts, H, center, sN):
            counts = half_counts[:]
            left = []
            nleft = sN[:H]
            def rec(pos, tight):
                if pos == H:
                    ls = ''.join(left)
                    pal = ls + (str(center) if center != -1 else '') + ls[::-1]
                    return pal if int(pal) > int(sN) else None
                lo = int(nleft[pos]) if tight else 0
                for d in range(lo, 10):
                    if counts[d] == 0:
                        continue
                    counts[d] -= 1
                    left.append(str(d))
                    r = rec(pos + 1, tight and d == int(nleft[pos]))
                    if r is not None:
                        left.pop(); counts[d] += 1; return r
                    left.pop(); counts[d] += 1
                return None
            return rec(0, True)
        best = None
        for mask in range(1, 512):
            S = [d for d in range(1, 10) if (mask >> (d - 1)) & 1]
            odd = [d for d in S if d % 2 == 1]
            if len(odd) > 1:
                continue
            center = odd[0] if odd else -1
            L = sum(S)
            half_counts = [0] * 10
            for d in S:
                half_counts[d] += d // 2
            H = sum(half_counts)
            ndig = len(str(n))
            if L < ndig:
                continue
            if L > ndig:
                left = ''.join(str(d) * half_counts[d] for d in range(1, 10))
                cand = left + (str(center) if center != -1 else '') + left[::-1]
            else:
                cand = build(half_counts, H, center, str(n))
            if cand is not None:
                val = int(cand)
                if val > n and (best is None or val < best):
                    best = val
        return best

