var specialPalindrome = function(n) {
    const N = BigInt(n);
    const build = (halfCounts, H, center, sN) => {
        const counts = halfCounts.slice();
        const left = [];
        const nleft = sN.slice(0, H);
        const rec = (pos, tight) => {
            if (pos === H) {
                const ls = left.join('');
                const pal = ls + (center !== -1 ? String(center) : '') + ls.split('').reverse().join('');
                return BigInt(pal) > BigInt(sN) ? pal : null;
            }
            const lo = tight ? Number(nleft[pos]) : 0;
            for (let d = lo; d < 10; d++) {
                if (counts[d] === 0) continue;
                counts[d]--; left.push(String(d));
                const r = rec(pos + 1, tight && d === Number(nleft[pos]));
                if (r !== null) { left.pop(); counts[d]++; return r; }
                left.pop(); counts[d]++;
            }
            return null;
        };
        return rec(0, true);
    };
    let best = null;
    const sN0 = String(n);
    for (let mask = 1; mask < 512; mask++) {
        const S = [];
        for (let d = 1; d <= 9; d++) if ((mask >> (d - 1)) & 1) S.push(d);
        const odd = S.filter(d => d % 2 === 1);
        if (odd.length > 1) continue;
        const center = odd.length ? odd[0] : -1;
        const L = S.reduce((a, b) => a + b, 0);
        const halfCounts = new Array(10).fill(0);
        for (const d of S) halfCounts[d] += Math.floor(d / 2);
        const H = halfCounts.reduce((a, b) => a + b, 0);
        const ndig = sN0.length;
        let cand = null;
        if (L < ndig) continue;
        if (L > ndig) {
            let leftStr = '';
            for (let d = 1; d <= 9; d++) leftStr += String(d).repeat(halfCounts[d]);
            cand = leftStr + (center !== -1 ? String(center) : '') + leftStr.split('').reverse().join('');
        } else {
            cand = build(halfCounts, H, center, sN0);
        }
        if (cand !== null) {
            const val = BigInt(cand);
            if (val > N && (best === null || val < best)) best = val;
        }
    }
    return Number(best);
};
